#!/bin/bash
# Deployment Verification Script
# Generated by deploy-prep-agent
# Usage: ./verify-deployment.sh <subdomain> [environment]

set -e

SUBDOMAIN="${1:-do-deal-relay}"
ENV="${2:-production}"

if [ -z "$SUBDOMAIN" ]; then
    echo "вќЊ Error: Subdomain required"
    echo "Usage: ./verify-deployment.sh <subdomain> [staging|production]"
    exit 1
fi

if [ "$ENV" == "staging" ]; then
    URL="https://do-deal-relay-staging.$SUBDOMAIN.workers.dev"
    echo "рџ”Ќ Verifying STAGING deployment"
else
    URL="https://do-deal-relay.$SUBDOMAIN.workers.dev"
    echo "рџ”Ќ Verifying PRODUCTION deployment"
fi

echo "URL: $URL"
echo ""

# Check if jq is available
if ! command -v jq &> /dev/null; then
    echo "вљ пёЏ  Warning: jq not found. Responses will not be pretty-printed."
    echo "   Install jq for better output: https://stedolan.github.io/jq/download/"
    JQ_AVAILABLE=false
else
    JQ_AVAILABLE=true
fi

echo "в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ"
echo "Testing 8 API Endpoints"
echo "в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ"
echo ""

FAILED=0

# Test 1: Health endpoint
echo "1пёЏвѓЈ  GET /health"
RESPONSE=$(curl -s -w "\n%{http_code}" "$URL/health")
HTTP_CODE=$(echo "$RESPONSE" | tail -n1)
BODY=$(echo "$RESPONSE" | sed '$d')

if [ "$HTTP_CODE" == "200" ]; then
    echo "   вњ… 200 OK"
    if [ "$JQ_AVAILABLE" = true ]; then
        echo "$BODY" | jq -C '.' | sed 's/^/   /'
        # Verify status is healthy
        if echo "$BODY" | jq -e '.status == "healthy"' > /dev/null 2>&1; then
            echo "   вњ“ Status: healthy"
        else
            echo "   вљ пёЏ  Status: $(echo "$BODY" | jq -r '.status')"
        fi
    else
        echo "   $BODY"
    fi
else
    echo "   вќЊ HTTP $HTTP_CODE"
    echo "   $BODY"
    ((FAILED++))
fi
echo ""

# Test 2: Metrics endpoint
echo "2пёЏвѓЈ  GET /metrics"
RESPONSE=$(curl -s -w "\n%{http_code}" "$URL/metrics")
HTTP_CODE=$(echo "$RESPONSE" | tail -n1)
BODY=$(echo "$RESPONSE" | sed '$d')

if [ "$HTTP_CODE" == "200" ]; then
    echo "   вњ… 200 OK"
    if echo "$BODY" | grep -q "deals_" > /dev/null 2>&1; then
        echo "   вњ“ Prometheus metrics found"
    fi
    # Show first few lines
    echo "$BODY" | head -6 | sed 's/^/   /'
else
    echo "   вќЊ HTTP $HTTP_CODE"
    echo "   $BODY"
    ((FAILED++))
fi
echo ""

# Test 3: Deals endpoint
echo "3пёЏвѓЈ  GET /deals"
RESPONSE=$(curl -s -w "\n%{http_code}" "$URL/deals")
HTTP_CODE=$(echo "$RESPONSE" | tail -n1)
BODY=$(echo "$RESPONSE" | sed '$d')

if [ "$HTTP_CODE" == "200" ]; then
    echo "   вњ… 200 OK"
    if [ "$JQ_AVAILABLE" = true ]; then
        COUNT=$(echo "$BODY" | jq '. | length')
        echo "   вњ“ $COUNT deals returned"
    else
        echo "   $BODY"
    fi
else
    echo "   вќЊ HTTP $HTTP_CODE"
    echo "   $BODY"
    ((FAILED++))
fi
echo ""

# Test 4: Deals JSON endpoint
echo "4пёЏвѓЈ  GET /deals.json"
RESPONSE=$(curl -s -w "\n%{http_code}" "$URL/deals.json")
HTTP_CODE=$(echo "$RESPONSE" | tail -n1)
BODY=$(echo "$RESPONSE" | sed '$d')

if [ "$HTTP_CODE" == "200" ]; then
    echo "   вњ… 200 OK"
    if [ "$JQ_AVAILABLE" = true ]; then
        if echo "$BODY" | jq -e '.schema_version' > /dev/null 2>&1; then
            SCHEMA=$(echo "$BODY" | jq -r '.schema_version')
            echo "   вњ“ Schema version: $SCHEMA"
        fi
        if echo "$BODY" | jq -e '.stats' > /dev/null 2>&1; then
            TOTAL=$(echo "$BODY" | jq '.stats.total')
            ACTIVE=$(echo "$BODY" | jq '.stats.active')
            echo "   вњ“ Stats: $TOTAL total, $ACTIVE active"
        fi
    fi
else
    echo "   вќЊ HTTP $HTTP_CODE"
    echo "   $BODY"
    ((FAILED++))
fi
echo ""

# Test 5: API Status endpoint
echo "5пёЏвѓЈ  GET /api/status"
RESPONSE=$(curl -s -w "\n%{http_code}" "$URL/api/status")
HTTP_CODE=$(echo "$RESPONSE" | tail -n1)
BODY=$(echo "$RESPONSE" | sed '$d')

if [ "$HTTP_CODE" == "200" ]; then
    echo "   вњ… 200 OK"
    if [ "$JQ_AVAILABLE" = true ]; then
        PHASE=$(echo "$BODY" | jq -r '.phase // "unknown"')
        LOCKED=$(echo "$BODY" | jq -r '.locked // "unknown"')
        echo "   вњ“ Phase: $PHASE, Locked: $LOCKED"
    else
        echo "   $BODY"
    fi
else
    echo "   вќЊ HTTP $HTTP_CODE"
    echo "   $BODY"
    ((FAILED++))
fi
echo ""

# Test 6: API Log endpoint
echo "6пёЏвѓЈ  GET /api/log"
RESPONSE=$(curl -s -w "\n%{http_code}" "$URL/api/log?count=10")
HTTP_CODE=$(echo "$RESPONSE" | tail -n1)
BODY=$(echo "$RESPONSE" | sed '$d')

if [ "$HTTP_CODE" == "200" ]; then
    echo "   вњ… 200 OK"
    if [ "$JQ_AVAILABLE" = true ]; then
        LOG_COUNT=$(echo "$BODY" | jq '.count // 0')
        echo "   вњ“ $LOG_COUNT log entries returned"
    else
        echo "   $BODY"
    fi
else
    echo "   вќЊ HTTP $HTTP_CODE"
    echo "   $BODY"
    ((FAILED++))
fi
echo ""

# Test 7: Manual discovery trigger (POST)
echo "7пёЏвѓЈ  POST /api/discover"
RESPONSE=$(curl -X POST -s -w "\n%{http_code}" "$URL/api/discover")
HTTP_CODE=$(echo "$RESPONSE" | tail -n1)
BODY=$(echo "$RESPONSE" | sed '$d')

if [ "$HTTP_CODE" == "200" ]; then
    echo "   вњ… 200 OK"
    if [ "$JQ_AVAILABLE" = true ]; then
        if echo "$BODY" | jq -e '.success' > /dev/null 2>&1; then
            echo "   вњ“ Discovery triggered successfully"
        fi
    else
        echo "   $BODY"
    fi
else
    # 202 is also acceptable (processing)
    if [ "$HTTP_CODE" == "202" ]; then
        echo "   вњ… 202 Accepted (processing)"
    else
        echo "   вќЊ HTTP $HTTP_CODE"
        echo "   $BODY"
        ((FAILED++))
    fi
fi
echo ""

# Test 8: Submit deal endpoint (POST)
echo "8пёЏвѓЈ  POST /api/submit"
TEST_CODE="VERIFY$(date +%s)"
RESPONSE=$(curl -X POST \
    -H "Content-Type: application/json" \
    -d "{\"code\":\"$TEST_CODE\",\"url\":\"https://verify.com\",\"source\":\"test\",\"metadata\":{\"title\":\"Test\",\"reward\":{\"type\":\"cash\",\"value\":50}}}" \
    -s -w "\n%{http_code}" \
    "$URL/api/submit")
HTTP_CODE=$(echo "$RESPONSE" | tail -n1)
BODY=$(echo "$RESPONSE" | sed '$d')

if [ "$HTTP_CODE" == "201" ]; then
    echo "   вњ… 201 Created"
    if [ "$JQ_AVAILABLE" = true ]; then
        DEAL_ID=$(echo "$BODY" | jq -r '.deal_id // "unknown"')
        echo "   вњ“ Deal created: $DEAL_ID"
    else
        echo "   $BODY"
    fi
else
    echo "   вќЊ HTTP $HTTP_CODE"
    echo "   $BODY"
    ((FAILED++))
fi
echo ""

echo "в”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ"

# Summary
if [ $FAILED -eq 0 ]; then
    echo ""
    echo "вњ… ALL 8 ENDPOINTS VERIFIED SUCCESSFULLY!"
    echo ""
    echo "Environment: $ENV"
    echo "URL: $URL"
    echo ""
    echo "Next steps:"
    echo "  вЂў Check Cloudflare Dashboard for trigger configuration"
    echo "  вЂў Monitor /health endpoint regularly"
    echo "  вЂў Set up optional secrets (GITHUB_TOKEN, TELEGRAM)"
    exit 0
else
    echo ""
    echo "вќЊ $FAILED ENDPOINT(S) FAILED"
    echo ""
    echo "Check the logs above for details."
    exit 1
fi
